SELECT 
FROM t_diet_record
WHERE user_id = #{userId}
  AND record_status = 0

    AND dining_time >= #{startTime}


    AND dining_time <= #{endTime}

ORDER BY dining_time DESC, record_id DESC
LIMIT #{limit}

